class Solution:
    def numberOfBeams(self, bank):
        counts = [row.count('1') for row in bank]
        m = len(counts)
        total = 0
        for i in range(m):
            if counts[i] == 0:
                continue
            for j in range(i + 1, m):
                if counts[j] > 0:
                    total += counts[i] * counts[j]
                    break
        return total

