var numberOfBeams = function(bank) {
    let total = 0;
    let prev = 0;
    for (const row of bank) {
        let cnt = 0;
        for (const ch of row) if (ch === '1') cnt++;
        if (cnt === 0) continue;
        total += prev * cnt;
        prev = cnt;
    }
    return total;
};
